local gS,SH
do
local function cPt(n) local p={} for i=0,n-1 do local a=(i/n)*math.pi*2 p[#p+1]=Vector2.new(math.cos(a),math.sin(a)) end return p end
local function pPt(s,o) local p={} for k=0,s-1 do local a=o+k*(2*math.pi/s) p[#p+1]=Vector2.new(math.cos(a),math.sin(a)) end return p end
local function hPt() local p={} for k=0,127 do local t=(k/128)*2*math.pi p[#p+1]=Vector2.new(16*math.sin(t)^3/17,-(13*math.cos(t)-5*math.cos(2*t)-2*math.cos(3*t)-math.cos(4*t))/17) end return p end
local SQ={Vector2.new(1,1),Vector2.new(-1,1),Vector2.new(-1,-1),Vector2.new(1,-1)}
local function pOf(u,r) local n=#u local pe=0 for i=1,n do local a=u[i]*r local b=u[(i%n)+1]*r pe=pe+(b-a).Magnitude end return pe end
local function bSm(u,c,r)
local sc={} for _,p in ipairs(u) do sc[#sc+1]=p*r end
local n=#sc local ls=c and n or n-1 local aL={0} for i=1,ls do local a=sc[i] local b=sc[(i%n)+1] aL[i+1]=aL[i]+math.sqrt((b.X-a.X)^2+(b.Y-a.Y)^2) end
local t=aL[ls+1] if t<=0 then return nil,0 end
return function(tg) local tt=math.clamp(tg,0,1)*t local lo,hi=1,ls while lo<hi do local md=math.floor((lo+hi)/2) if aL[md+1]<tt then lo=md+1 else hi=md end end local s=lo local a=sc[s] local b=sc[(s%n)+1] local sL=aL[s+1]-aL[s] local u2=sL>0 and(tt-aL[s])/sL or 0 u2=math.clamp(u2,0,1) local ps=Vector2.new(a.X+(b.X-a.X)*u2,a.Y+(b.Y-a.Y)*u2) local dr=Vector2.new(b.X-a.X,b.Y-a.Y) if dr.Magnitude<0.0001 then dr=Vector2.new(1,0) end return ps,dr.Unit end,t
end
local function pRg(pl,u,c,cx,cy,cz,r,bH,th,cnt) local ev,pe=bSm(u,c,r) if not ev then return end local bL=(pe/math.max(1,cnt))*1.06 for k=0,cnt-1 do local ps,dr=ev((k+0.5)/cnt) local wm=Vector3.new(cx+ps.X,cy,cz+ps.Y) local wd=Vector3.new(dr.X,0,dr.Y) pl[#pl+1]={cframe=CFrame.lookAt(wm,wm+wd),size=Vector3.new(th,bH,bL)} end end
local function pBn(u,r) local pts={} local mX,mxX,mZ,mxZ=1e9,-1e9,1e9,-1e9 for _,p in ipairs(u) do local x,z=p.X*r,p.Y*r pts[#pts+1]={x,z} if x<mX then mX=x end if x>mxX then mxX=x end if z<mZ then mZ=z end if z>mxZ then mxZ=z end end return pts,mX,mxX,mZ,mxZ end
local function mI(pts) local n=#pts return function(px,pz) local c=false local j=n for i=1,n do local xi,zi=pts[i][1],pts[i][2] local xj,zj=pts[j][1],pts[j][2] if((zi>pz)~=(zj>pz))and(px<(xj-xi)*(pz-zi)/((zj-zi)+1e-12)+xi)then c=not c end j=i end return c end end
local function fGl(pl,u,cx,cy,cz,r,th,st) local pts,mX,mxX,mZ,mxZ=pBn(u,r) local ins=mI(pts) local gx=mX+st*0.5 while gx<=mxX+1e-6 do local gz=mZ+st*0.5 while gz<=mxZ+1e-6 do if ins(gx,gz) then pl[#pl+1]={cframe=CFrame.new(cx+gx,cy,cz+gz),size=Vector3.new(st,th,st)} end gz=gz+st end gx=gx+st end end
local function fSt(pl,u,cx,cy,cz,r,th,st) local pts,mX,mxX,mZ,mxZ=pBn(u,r) local ins=mI(pts) local sp=math.max(st*0.30,(mxX-mX)/240) local gz=mZ+st*0.5 while gz<=mxZ+1e-6 do local sS2=nil local pI=false local x=mX local function fl(x0,x1) local w=x1-x0 if w>0 then pl[#pl+1]={cframe=CFrame.new(cx+(x0+x1)/2,cy,cz+gz),size=Vector3.new(w+sp,th,st*1.02)} end end while x<=mxX+1e-6 do local i2=ins(x,gz) if i2 and not pI then sS2=x elseif(not i2)and pI then fl(sS2,x-sp) sS2=nil end pI=i2 x=x+sp end if pI and sS2 then fl(sS2,mxX) end gz=gz+st end end
local function fCp(pl,u,cx,cy,cz,r,th,st) if cFM=="grid" then fGl(pl,u,cx,cy,cz,r,th,st) else fSt(pl,u,cx,cy,cz,r,th,st) end end
local function bEx(pl,u,cx,cy,cz,r,h,th,cnt,cT,cB) local pe=pOf(u,r) local sg=pe/math.max(1,cnt) pRg(pl,u,true,cx,cy,cz,r,h,th,cnt) if cT then fCp(pl,u,cx,cy+h/2-th/2,cz,r,th,sg) end if cB then fCp(pl,u,cx,cy-h/2+th/2,cz,r,th,sg) end end
local function bCu(pl,cx,cy,cz,r,th,cnt,cT,cB) local pF=math.max(1,math.floor(cnt/6+0.5)) local gN=math.max(1,math.round(math.sqrt(pF))) local hf=r local st=(2*hf)/gN local bs2=st*1.02 local function f(ax,v) for r2=0,gN-1 do for c2=0,gN-1 do local u2=-hf+st*c2+st/2 local v2=-hf+st*r2+st/2 if ax=="y" then pl[#pl+1]={cframe=CFrame.new(cx+u2,cy+v,cz+v2),size=Vector3.new(bs2,th,bs2)} elseif ax=="x" then pl[#pl+1]={cframe=CFrame.new(cx+v,cy+u2,cz+v2),size=Vector3.new(th,bs2,bs2)} else pl[#pl+1]={cframe=CFrame.new(cx+u2,cy+v2,cz+v),size=Vector3.new(bs2,bs2,th)} end end end end f("x",hf) f("x",-hf) f("z",hf) f("z",-hf) if cT then f("y",hf) end if cB then f("y",-hf) end end
local function bSp(pl,cx,cy,cz,r,th,cnt) cnt=math.max(8,cnt) local L=math.max(3,math.round(math.sqrt(cnt/2))) local M=math.max(6,L*2) local lS=(2*math.pi)/M local loS=math.pi/L local sL=r*lS*1.08 local sW=r*loS*1.08 local c=CFrame.new(cx,cy,cz) for li=0,L-1 do local phi=loS*li local rR=CFrame.Angles(0,phi,0) for ai=0,M-1 do local a=lS*ai local lCF=CFrame.new(0,r*math.cos(a),r*math.sin(a))*CFrame.Angles(a,0,0) pl[#pl+1]={cframe=c*rR*lCF,size=Vector3.new(sW,th,sL)} end end end
local function aHE(pl,cx,cy,cz,r,aL,th,cnt,tp) cnt=math.max(8,cnt) local L=math.max(3,math.round(math.sqrt(cnt/2))) local M=math.max(6,L*2) local lS=(2*math.pi)/M local loS=math.pi/L local sW=r*loS*1.10 local ys=aL/r local c=CFrame.new(cx,cy,cz) local function cP2(a) return r*math.cos(a)*ys,r*math.sin(a) end for li=0,L-1 do local phi=loS*li local rR=CFrame.Angles(0,phi,0) for ai=0,M-1 do local a=lS*ai local ca=math.cos(a) local kp=tp and(ca>=-1e-6)or((not tp)and(ca<=1e-6)) if kp then local yy=r*ca*ys local y0,z0=cP2(a-lS/2) local y1,z1=cP2(a+lS/2) local dy,dz=y1-y0,z1-z0 local sL=math.sqrt(dy*dy+dz*dz) if sL<1e-6 then dy,dz,sL=0,1,1 end local nx,ny,nz=0,dz,-dy local nm=math.sqrt(ny*ny+nz*nz) if nm<1e-9 then nm=1 end local lCF=CFrame.fromMatrix(Vector3.new(0,yy,r*math.sin(a)),Vector3.new(1,0,0),Vector3.new(nx,ny/nm,nz/nm),Vector3.new(0,dy/sL,dz/sL)) pl[#pl+1]={cframe=c*rR*lCF,size=Vector3.new(sW,th,sL*1.10)} end end end end
local function bPy(pl,cx,cy,cz,r,h,th,cnt,p01,cB) local hs=r local ex=0.5+p01*2.5 local ly=math.clamp(math.floor(cnt/4+0.5),3,160) local lH=h/ly local fs={{dir=Vector3.new(1,0,0),side=Vector3.new(0,0,1)},{dir=Vector3.new(-1,0,0),side=Vector3.new(0,0,1)},{dir=Vector3.new(0,0,1),side=Vector3.new(1,0,0)},{dir=Vector3.new(0,0,-1),side=Vector3.new(1,0,0)}} local function pr(t) return hs*((1-t)^ex) end for _,f in ipairs(fs) do for i=0,ly-1 do local t0=i/ly local t1=(i+1)/ly local tc=(i+0.5)/ly local dc=pr(tc) local yc=(cy-h/2)+tc*h local pBt=f.dir*pr(t0)+Vector3.new(0,(cy-h/2)+t0*h,0) local pTp=f.dir*pr(t1)+Vector3.new(0,(cy-h/2)+t1*h,0) local u=pTp-pBt local sL=u.Magnitude if sL<1e-4 then u=Vector3.new(0,1,0) sL=lH else u=u.Unit end local v=f.side local n2=u:Cross(v) if n2:Dot(f.dir)<0 then v=-v n2=u:Cross(v) end n2=n2.Unit v=v.Unit local w=2*dc if w<1e-3 then w=sL*0.5 end pl[#pl+1]={cframe=CFrame.fromMatrix(Vector3.new(cx,0,cz)+f.dir*dc+Vector3.new(0,yc,0),v,n2),size=Vector3.new(w*1.04,th,sL*1.05)} end end if cB then fCp(pl,SQ,cx,cy-h/2+th/2,cz,hs,th,(2*hs)/math.max(4,ly)) end end
local function bCp(pl,cx,cy,cz,r,h,th,cnt,p01) local c=cPt(96) local cpL=r*(1+p01*1.5) local bH=math.max(h,0) if bH>0.01 then pRg(pl,c,true,cx,cy,cz,r,bH,th,cnt) end aHE(pl,cx,cy+bH/2,cz,r,cpL,th,cnt,true) aHE(pl,cx,cy-bH/2,cz,r,cpL,th,cnt,false) end
SH={{label="Circulo",icon="circle",kind="extrude",pts=function()return cPt(96)end,caps="both",fillable=true,useHeight=true,useCount=true,usePoint=false},{label="Cuadrado",icon="square",kind="extrude",pts=function()return pPt(4,math.pi/4)end,caps="both",fillable=true,useHeight=true,useCount=true,usePoint=false},{label="Corazon",icon="heart",kind="extrude",pts=hPt,caps="both",fillable=true,useHeight=true,useCount=true,usePoint=false},{label="Cubo",icon="cube",kind="cube3d",caps="both",fillable=false,useHeight=false,useCount=true,usePoint=false},{label="Esfera",icon="sphere",kind="sphere3d",caps=false,fillable=false,useHeight=false,useCount=true,usePoint=false},{label="Piramide",icon="pyramid",kind="pyramid",caps="bottom",fillable=true,useHeight=true,useCount=true,usePoint=true,pointy=true},{label="Capsula",icon="capsule",kind="capsule",caps=false,fillable=false,useHeight=true,useCount=true,usePoint=true,pointy=true}}
gS=function(d,c,P) local pl={} if not c then return pl end local cx,cy,cz=c.X,c.Y,c.Z local k=d.kind if k=="extrude" then bEx(pl,d.pts(),cx,cy,cz,P.radius,P.height,P.thick,P.count,P.capTop,P.capBottom) elseif k=="cube3d" then bCu(pl,cx,cy,cz,P.radius,P.thick,P.count,P.capTop,P.capBottom) elseif k=="sphere3d" then bSp(pl,cx,cy,cz,P.radius,P.thick,P.count) elseif k=="pyramid" then bPy(pl,cx,cy,cz,P.radius,P.height,P.thick,P.count,P.point,P.capBottom) elseif k=="capsule" then bCp(pl,cx,cy,cz,P.radius,P.height,P.thick,P.count,P.point) end if hR then local pv=CFrame.new(cx,cy,cz) local rt=pv*sR*pv:Inverse() for _,s in ipairs(pl) do s.cframe=rt*s.cframe end end return pl end
end

local dI
do
local function dL(par,x1,y1,x2,y2,col) local dx,dy=x2-x1,y2-y1 local ln=math.sqrt(dx*dx+dy*dy) if ln<1 then return end m("Frame",par,{AnchorPoint=Vector2.new(0.5,0.5),Position=UDim2.fromOffset((x1+x2)/2,(y1+y2)/2),Size=UDim2.fromOffset(ln,2),BorderSizePixel=0,BackgroundColor3=col,Rotation=math.deg(math.atan2(dy,dx))}) end
dI=function(cn,d,col) for _,c in ipairs(cn:GetChildren()) do if not c:IsA("UICorner")and not c:IsA("UIStroke")then c:Destroy() end end local bsz=cn.AbsoluteSize.X if bsz<=0 then bsz=30 end local R=(bsz/2)-3 local cx2,cy2=bsz/2,bsz/2 local ic=d.icon if ic=="circle"then local rn=m("Frame",cn,{AnchorPoint=Vector2.new(0.5,0.5),Position=UDim2.fromScale(0.5,0.5),Size=UDim2.fromOffset(R*2,R*2),BackgroundTransparency=1}) co(rn,999) m("UIStroke",rn,{Color=col,Thickness=2,ApplyStrokeMode=Enum.ApplyStrokeMode.Border}) elseif ic=="square"then local s=R*0.85 dL(cn,cx2-s,cy2-s,cx2+s,cy2-s,col) dL(cn,cx2+s,cy2-s,cx2+s,cy2+s,col) dL(cn,cx2+s,cy2+s,cx2-s,cy2+s,col) dL(cn,cx2-s,cy2+s,cx2-s,cy2-s,col) elseif ic=="sphere"then local rn=m("Frame",cn,{AnchorPoint=Vector2.new(0.5,0.5),Position=UDim2.fromScale(0.5,0.5),Size=UDim2.fromOffset(R*2,R*2),BackgroundTransparency=1}) co(rn,999) m("UIStroke",rn,{Color=col,Thickness=2,ApplyStrokeMode=Enum.ApplyStrokeMode.Border}) dL(cn,cx2-R,cy2,cx2+R,cy2,col) elseif ic=="cube"then local s=R*0.6 local o=R*0.5 local fr={{-s,-s},{s,-s},{s,s},{-s,s}} local bk={} for i,c2 in ipairs(fr) do bk[i]={c2[1]+o,c2[2]-o} end for i=1,4 do local a,b2=fr[i],fr[(i%4)+1] local a2,b3=bk[i],bk[(i%4)+1] dL(cn,cx2+a[1],cy2+a[2],cx2+b2[1],cy2+b2[2],col) dL(cn,cx2+a2[1],cy2+a2[2],cx2+b3[1],cy2+b3[2],col) dL(cn,cx2+a[1],cy2+a[2],cx2+a2[1],cy2+a2[2],col) end elseif ic=="pyramid"then local tx,ty=cx2,cy2-R local blx,bly=cx2-R,cy2+R*0.8 local brx,bry=cx2+R,cy2+R*0.8 dL(cn,tx,ty,blx,bly,col) dL(cn,tx,ty,brx,bry,col) dL(cn,blx,bly,brx,bry,col) dL(cn,tx,ty,cx2+R*0.35,bry,col) elseif ic=="capsule"then local st=m("Frame",cn,{AnchorPoint=Vector2.new(0.5,0.5),Position=UDim2.fromScale(0.5,0.5),Size=UDim2.fromOffset(R*1.2,R*2),BackgroundTransparency=1}) co(st,999) m("UIStroke",st,{Color=col,Thickness=2,ApplyStrokeMode=Enum.ApplyStrokeMode.Border}) elseif ic=="heart"then local sc=R*0.82 local pts={} local N=32 for k2=0,N-1 do local t=(k2/N)*2*math.pi local px=16*math.sin(t)^3 local py=-(13*math.cos(t)-5*math.cos(2*t)-2*math.cos(3*t)-math.cos(4*t)) pts[k2+1]={cx2+px*sc/17,cy2+py*sc/17} end for i=1,N do local a2=pts[i] local b2=pts[(i%N)+1] dL(cn,a2[1],a2[2],b2[1],b2[2],col) end end end
end

