local rP=function() return {radius=math.max(PM.radius,tonumber(BI.bR and BI.bR.Text)or 20),height=math.max(PM.height,tonumber(BI.bY and BI.bY.Text)or 8),thick=math.max(PM.thick,tonumber(BI.bT and BI.bT.Text)or 1),count=math.max(PM.count,math.floor(tonumber(BI.bS and BI.bS.Text)or 120)),point=math.clamp(tonumber(BI.bP and BI.bP.Text)or 0,0,1),capTop=cT,capBottom=cB} end
local cD=m("Part",eF,{Size=Vector3.new(4,4,4),Transparency=1,Color=T.accent,Anchored=true,CanCollide=false,CanQuery=false,Material=Enum.Material.Plastic,Position=Vector3.new(0,-9999,0)})
local rB={} local function bR(h,vF) local f=m("Frame",PB,{Size=UDim2.new(1,0,0,h),BackgroundTransparency=1,LayoutOrder=#rB+1}) rB[#rB+1]={frame=f,vis=vF} return f end
