local function bH(b,f) local h=false local function g() if h then return end h=true f() task.spawn(function() local d=0.35 task.wait(d) while h do f() task.wait(d) d=math.max(0.03,d*0.75) end end) end local function sp() h=false end b.MouseButton1Down:Connect(g) b.MouseButton1Up:Connect(sp) b.MouseLeave:Connect(sp) end
